import{_ as o,o as t,c as n,a2 as s}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"RFC 0017 — Plugin starter template & example plugins","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0017-plugin-starter-and-examples.md","filePath":"rfcs/0017-plugin-starter-and-examples.md"}'),i={name:"rfcs/0017-plugin-starter-and-examples.md"};function a(r,e,d,l,c,p){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="rfc-0017-—-plugin-starter-template-example-plugins" tabindex="-1">RFC 0017 — Plugin starter template &amp; example plugins <a class="header-anchor" href="#rfc-0017-—-plugin-starter-template-example-plugins" aria-label="Permalink to &quot;RFC 0017 — Plugin starter template &amp; example plugins&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>bin/sv</code> + <code>bin/helpers.ts</code> (a new <code>plugin new</code> command), <code>@sovereignfs/sdk</code> npm publishability (<strong>prerequisite</strong>), <code>docs/plugin-development.md</code>, <code>CONTRIBUTING.md</code>, the registry (<code>registry/plugins.json</code>, Task 0.5.19), and <strong>external GitHub repos</strong> (a template + example plugins) under the <code>sovereignfs</code> org; builds on the plugin model (SRS §3.5/§3.9), RFC 0001 (overlay), RFC 0014 (minimal shell), RFC 0015 (notifications), RFC 0010 (test organization — examples double as fixtures)<br><strong>Incorporated into plan:</strong> Yes — scheduled as roadmap Task 0.5.28; documentation-first. This RFC defines the starter/example strategy, contents, naming, the hard prerequisite, and the example set. The template and example repos are external repos created as execution after acceptance; SRS requirement IDs, scheduling, and task allocation are deferred.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Give plugin authors a real on-ramp. A Sovereign plugin is only about five files, but today a newcomer has to <em>know which five</em> — the manifest field rules, the SDK-only import boundary, the slug-prefixed <code>tenant_id</code> DB conventions, and the naming conventions — by reading docs and copying a built-in plugin. This RFC proposes:</p><ul><li>a <strong>canonical starter skeleton</strong> (one source of truth) delivered three ways: a <strong>GitHub template repo</strong> (<code>Use this template</code>), a <strong><code>sv plugin new &lt;name&gt;</code></strong> CLI command, and an <strong><code>npm create @sovereignfs/plugin</code></strong> initializer;</li><li>a small set of <strong>example plugins</strong> — purpose-built, single-capability demos (<em>not</em> the real first-party plugins) that also serve as <strong>runtime test fixtures</strong>;</li><li>an explicit <strong>prerequisite</strong>: making <code>@sovereignfs/sdk</code> npm-installable, without which a standalone repo cannot depend on the SDK.</li></ul><p>The plugin system is the product; &quot;five files, but you must know which five&quot; is exactly the friction a starter removes.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p><code>sv</code> has <code>plugin add</code> and <code>plugin remove</code> but <strong>no scaffold command</strong> — there is no <code>sv plugin new</code>, no template, no initializer. Every new plugin starts by reading <code>docs/plugin-development.md</code> and reverse-engineering a built-in plugin. That is a high bar for the one thing the platform most wants to encourage. A starter that emits a correct manifest, a working <code>app/</code> route, the SDK/UI wiring, and the DB conventions — and example plugins that show one capability each — turns plugin authoring from &quot;study the platform&quot; into &quot;fork and edit.&quot;</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>A plugin is ~5 files.</strong> <code>manifest.json</code> + <code>package.json</code> + <code>app/page.tsx</code>, with optional <code>icon.svg</code> and <code>db/schema.ts</code> (reference: <code>plugins/launcher/</code>). The manifest required fields and rules live in <code>packages/manifest/src/schema.ts</code> (incl. <code>repository</code> required for <code>type: sovereign | community</code>).</li><li><strong>No scaffold command.</strong> <code>bin/sv.ts</code> / <code>bin/helpers.ts</code> implement <code>install</code>/<code>generate</code>/<code>build</code>/<code>dev</code>/<code>serve</code> and <code>plugin add</code>/<code>plugin remove</code> — but nothing that <em>creates</em> a plugin. <code>plugin add &lt;repo&gt;</code> shallow-clones a repo, keys the destination off the manifest <code>id</code>, validates, and composes.</li><li><strong>Install + discovery today.</strong> <code>scripts/install-plugins.ts</code> reads <code>sovereign.plugins.json</code> (<code>{ id, repository }[]</code>) and shallow-clones each into <code>plugins/&lt;id&gt;/</code>; the <code>.gitignore</code> allowlist keeps only <code>console</code>/<code>launcher</code>/ <code>account</code> committed. The planned <strong>registry</strong> (<code>registry/plugins.json</code>, Task 0.5.18) is the future discovery layer with a submission/review process.</li><li><strong>Monorepo-only resolution.</strong> In-repo plugins use <code>@sovereignfs/sdk</code> / <code>@sovereignfs/ui</code> as <code>workspace:*</code>, <code>next</code>/<code>react</code> as <code>catalog:</code> (<code>pnpm-workspace.yaml</code>), and rely on the runtime&#39;s <code>transpilePackages</code> (<code>runtime/next.config.ts</code>). <strong>None of these exist in a standalone repo</strong> — a template must use real npm versions.</li><li><strong>The blocker.</strong> <code>@sovereignfs/ui</code> is npm-publishable, but <strong><code>@sovereignfs/sdk</code> is not yet</strong> — its <code>dist</code> imports the private <code>@sovereignfs/db</code>/<code>@sovereignfs/mailer</code> (CLAUDE.md, Task 0.5.8 caveat). A standalone template can&#39;t <code>npm install @sovereignfs/sdk</code> until that is resolved.</li><li><strong>Conventions</strong> — GitHub org <code>sovereignfs</code>; repos use clear <code>sovereign-*</code> names; plugin ids use <code>fs.sovereign.*</code> for first-party platform/default/example plugins and community reverse-DNS for third-party plugins; npm scope <code>@sovereignfs/*</code>. The current first-party repository map is <a href="./../repositories.html"><code>docs/repositories.md</code></a>.</li></ul><h2 id="prerequisite-—-sovereignfs-sdk-on-npm" tabindex="-1">Prerequisite — <code>@sovereignfs/sdk</code> on npm <a class="header-anchor" href="#prerequisite-—-sovereignfs-sdk-on-npm" aria-label="Permalink to &quot;Prerequisite — `@sovereignfs/sdk` on npm&quot;">​</a></h2><p>The standalone template and the npm initializer <strong>depend on</strong> publishing <code>@sovereignfs/sdk</code> (either bundle <code>db</code>/<code>mailer</code> into the SDK <code>dist</code> via tsup <code>noExternal</code>, or publish those packages) — the follow-up already flagged for Tasks 0.5.07/0.5.19. This RFC states it as a <strong>blocking dependency</strong> rather than glossing over it. <code>@sovereignfs/ui</code> is already publishable. <strong>Superseded by RFC 0023:</strong> the SDK&#39;s distribution model is now decided there — publish a <strong>types-first contract</strong> (host-provided impls, no <code>db</code>/<code>mailer</code> dependency) rather than bundling the private deps; read 0023 for the prerequisite&#39;s actual shape. <strong>Partial unblock:</strong> the <code>sv plugin new</code> path can scaffold <strong>in-monorepo</strong> today (where <code>workspace:*</code> resolves), so the CLI mechanism can ship ahead of the npm work; only the external template repo and the initializer truly require the published SDK.</p><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="the-canonical-skeleton-single-source-of-truth" tabindex="-1">The canonical skeleton (single source of truth) <a class="header-anchor" href="#the-canonical-skeleton-single-source-of-truth" aria-label="Permalink to &quot;The canonical skeleton (single source of truth)&quot;">​</a></h3><p>Define the minimal, well-commented starter <strong>once</strong> and have all three mechanisms emit it (no drift):</p><ul><li><code>manifest.json</code> — every field annotated; <code>type: community</code>, <code>repository</code> set, a sensible <code>routePrefix</code> and <code>permissions</code> (<code>auth:session</code>, <code>db:readWrite</code>).</li><li><code>package.json</code> — <strong>npm-versioned</strong> <code>@sovereignfs/sdk</code> / <code>@sovereignfs/ui</code> and literal <code>next</code>/<code>react</code> versions (<strong>not</strong> <code>catalog:</code> / <code>workspace:*</code>).</li><li><code>tsconfig.json</code> — static (inline, or extending a published <code>@sovereignfs/tsconfig</code>).</li><li><code>app/page.tsx</code> + <code>app/layout.tsx</code> — a working route showing <strong>SDK-only</strong> imports, a <code>@sovereignfs/ui</code> component, and a <code>--sv-</code> token (modelling the conventions).</li><li><code>db/schema.ts</code> — one slug-prefixed table with <code>tenant_id</code> (dialect-agnostic).</li><li><code>icon.svg</code>, <code>.gitignore</code> (generated copies), <code>.env.example</code>, <code>README.md</code>, and CI (lint / format / build).</li></ul><p>Recommendation: the <strong>template repo is the canonical skeleton</strong>; <code>sv plugin new</code> and the initializer scaffold from it (degit-style fetch, or a vendored-and-synced copy). Keeping those in sync is an open question.</p><h3 id="three-delivery-mechanisms" tabindex="-1">Three delivery mechanisms <a class="header-anchor" href="#three-delivery-mechanisms" aria-label="Permalink to &quot;Three delivery mechanisms&quot;">​</a></h3><ul><li><strong>GitHub template repo</strong> — <code>sovereignfs/sovereign-plugin-template</code> with a <code>Use this template</code> button. Zero-maintenance, discoverable, ideal for the &quot;develop in my own repo&quot; path.</li><li><strong><code>sv plugin new &lt;name&gt;</code></strong> — a scaffold command beside <code>plugin add</code>/<code>remove</code> in <code>bin/sv.ts</code>: derive the <code>id</code>, write the skeleton (into <code>plugins/&lt;id&gt;/</code> for monorepo dev). Works <strong>before</strong> the SDK is on npm.</li><li><strong><code>npm create @sovereignfs/plugin</code></strong> — a prompted initializer (name, id, permissions, shell) for users outside the repo. Depends on the SDK prerequisite.</li></ul><h3 id="example-plugins-capability-demos" tabindex="-1">Example plugins (capability demos) <a class="header-anchor" href="#example-plugins-capability-demos" aria-label="Permalink to &quot;Example plugins (capability demos)&quot;">​</a></h3><p>Purpose-built, single-concept plugins live together in <a href="https://github.com/sovereignfs/sovereign-plugins-examples" target="_blank" rel="noreferrer"><code>sovereignfs/sovereign-plugins-examples</code></a> with ids under <code>fs.sovereign.example.*</code>. Each is the <strong>smallest</strong> thing that teaches one ability — explicitly <strong>teaching artifacts</strong>, distinct from real first-party product plugins such as Tasks. Candidate set (recommend shipping <strong>a couple</strong> first — <code>example-basic</code> + <code>example-api</code>):</p><ul><li><strong><code>example-basic</code></strong> — default shell + <code>auth:session</code> + <code>db:readWrite</code> (one slug-prefixed <code>tenant_id</code> table) + <code>@sovereignfs/ui</code> + tokens. The &quot;normal plugin&quot; reference.</li><li><strong><code>example-api</code></strong> — <code>apiProvider: true</code> with a public <code>/api/&lt;slug&gt;</code> endpoint and API-key auth (PLT-16). The &quot;serve an API&quot; reference.</li><li><strong><code>example-overlay</code></strong> — <code>shell: overlay</code> dialog + <code>shellConfig.overlaySize</code> (RFC 0001).</li><li><strong><code>example-minimal</code></strong> — <code>shell: minimal</code> full-bleed (depends on RFC 0014).</li><li><strong><code>example-notify</code></strong> — <code>notifications:send</code> into the Notification Center (depends on RFC 0015).</li></ul><h3 id="examples-as-test-fixtures-dual-use" tabindex="-1">Examples as test fixtures (dual-use) <a class="header-anchor" href="#examples-as-test-fixtures-dual-use" aria-label="Permalink to &quot;Examples as test fixtures (dual-use)&quot;">​</a></h3><p>Because each demo is minimal and exercises exactly one capability, the same repos make ideal <strong>runtime test fixtures</strong>:</p><ul><li><code>example-basic</code> → manifest validation + default composition + db/auth;</li><li><code>example-api</code> → <code>apiProvider</code> resolution + the public <code>/api</code> namespace (<code>findApiProvider</code>, <code>decideApiNamespace</code>);</li><li><code>example-overlay</code> / <code>example-minimal</code> → the shell-mode composition branches in <code>scripts/generate-registry.ts</code>;</li><li>an <code>adminOnly</code> variant → the route guard (<code>decidePluginRoute</code>, 403/404).</li></ul><p>Consequence: fixtures must be <strong>deterministic and version-pinned</strong> for CI, which argues for an <strong>in-monorepo copy/pin</strong> (or a pinned clone) rather than a floating external clone. Cross-reference <strong>RFC 0010</strong> (test organization) for where fixtures live (<code>/__tests__/</code> cross-boundary vs per-package). The exact location is an open question below.</p><h3 id="naming-conventions" tabindex="-1">Naming &amp; conventions <a class="header-anchor" href="#naming-conventions" aria-label="Permalink to &quot;Naming &amp; conventions&quot;">​</a></h3><p>Consolidate the rules so the starter models them: org <code>sovereignfs</code>, clear <code>sovereign-*</code> repository names, <code>fs.sovereign.*</code> for first-party platform/default/example plugin ids, community reverse-DNS for third-party ids, and npm scope <code>@sovereignfs/*</code>.</p><h3 id="tie-to-the-registry-task-0-5-19" tabindex="-1">Tie to the registry (Task 0.5.19) <a class="header-anchor" href="#tie-to-the-registry-task-0-5-19" aria-label="Permalink to &quot;Tie to the registry (Task 0.5.19)&quot;">​</a></h3><p>The template and the examples are natural first entries / discovery anchors for <code>registry/plugins.json</code>. The contributor loop becomes: <strong>Use this template → develop (<code>sv plugin add</code> / <code>pnpm dev</code>) → publish → register.</strong> <code>sv plugin new</code> and the docs point at the registry.</p><h2 id="dev-flow" tabindex="-1">Dev flow <a class="header-anchor" href="#dev-flow" aria-label="Permalink to &quot;Dev flow&quot;">​</a></h2><p>Scaffold (template repo / <code>sv plugin new</code> / initializer) → install into a local Sovereign (<code>sv plugin add &lt;repo&gt;</code> or a <code>sovereign.plugins.json</code> entry) → <code>pnpm dev</code> (HMR via re-copy) → publish the repo → submit to the registry.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>In-monorepo <code>examples/</code> directory only</strong> (no external repos). Rejected as the end state — the goal is real, forkable repos a developer can use as a template — but <strong>noted as the interim</strong> if the SDK isn&#39;t published in time (and it doubles as the fixtures location, see RFC 0010).</li><li><strong>A single mechanism.</strong> Rejected — the template repo, the CLI, and the npm initializer serve different audiences (own-repo devs, monorepo devs, and prompted newcomers). One shared skeleton keeps them consistent.</li><li><strong>&quot;Just copy a built-in plugin / the docs.&quot;</strong> The status quo. Rejected — drift between copies, no <code>Use this template</code> discoverability, no guided prompts.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Skeleton sync</strong> — canonical template repo vs a vendored-in-monorepo copy the CLI/initializer read; how to keep them from diverging.</li><li><strong>How many examples</strong> to ship first (recommend two).</li><li><strong><code>sv plugin new</code> target</strong> — only <code>plugins/</code> (monorepo), or also a standalone directory?</li><li><strong>Template versioning</strong> — how the skeleton tracks <code>minPlatformVersion</code> as the platform evolves.</li><li><strong>Fixture location</strong> — do the examples live as external repos pinned/cloned for CI, as an in-monorepo copy used directly as fixtures (RFC 0010), or both kept in sync?</li><li><strong>Requirement IDs</strong> — proposed entries, deferred until accepted.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Prerequisite:</strong> make <code>@sovereignfs/sdk</code> npm-installable (bundle or publish <code>db</code>/<code>mailer</code>).</li><li>Build the <strong>canonical skeleton</strong> + the <strong>template repo</strong>.</li><li>Add <strong><code>sv plugin new</code></strong> consuming the skeleton (can land first, in-monorepo).</li><li>Ship the <strong>npm initializer</strong>.</li><li>Build the first couple of <strong>example repos</strong> (and wire them as test fixtures).</li><li><strong>Register</strong> the template + examples (Task 0.5.19).</li></ol><p>Documentation-first now; nothing above is built in this RFC.</p><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; one canonical skeleton via template repo + <code>sv plugin new</code> + npm initializer; capability-demo example plugins that double as test fixtures; SDK-npm publishability as an explicit prerequisite; documentation-first.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Accepted; scheduled in the roadmap as Task 0.5.28.</td></tr></tbody></table>',42)])])}const h=o(i,[["render",a]]);export{u as __pageData,h as default};
